1	import * as http from 'node:http';
2	import { z } from 'zod';
3	import { MAX_FRAME, PluginError } from '@ax/core';
4	import {
5	  WORKSPACE_ACTION_PATHS,
6	  WORKSPACE_TIMEOUTS_MS,
7	  WorkspaceApplyRequestSchema,
8	  WorkspaceApplyResponseSchema,
9	  WorkspaceDiffRequestSchema,
10	  WorkspaceDiffResponseSchema,
11	  WorkspaceErrorEnvelopeSchema,
12	  WorkspaceListRequestSchema,
13	  WorkspaceListResponseSchema,
14	  WorkspaceReadRequestSchema,
15	  WorkspaceReadResponseSchema,
16	  type WorkspaceActionName,
17	} from '@ax/workspace-protocol';
18	import { WorkspaceServerUnavailableError } from './errors.js';
19	
20	// ---------------------------------------------------------------------------
21	// Host-side HTTP client for @ax/workspace-git-http. Sibling of
22	// `packages/ipc-protocol/src/ipc-client.ts` — same retry+timeout shape,
23	// but HTTP-only (no unix transport) and a static service-token auth model
24	// (no session token, no parseRunnerEndpoint).
25	//
26	// Per-action surface (apply/read/list/diff). Each method:
27	//   - POSTs JSON to /workspace.<action> on the configured baseUrl.
28	//   - Authorizes with `Authorization: Bearer ${token}`.
29	//   - Zod-parses the response against the matching schema from
30	//     @ax/workspace-protocol.
31	//   - Maps non-2xx → typed error (see error mapping below).
32	//
33	// Retry + timeout policy:
34	//   - Connection errors (ECONNREFUSED/RESET/EPIPE/ENOTFOUND/EHOSTUNREACH/
35	//     ENETUNREACH/ETIMEDOUT, plus AbortError as timeout) → retry with
36	//     exponential backoff (100, 200, 400, 800, ... cap 30 s).
37	//   - 5xx → retry with the same backoff. The host plugin treats this as
38	//     "server's having a moment, try again."
39	//   - 4xx → never retry. Translates to PluginError inside the client so the
40	//     host plugin / orchestrator can react (e.g., parent-mismatch → rebase).
41	//   - Per-action timeout from WORKSPACE_TIMEOUTS_MS, overridable via opts.
42	//
43	// Error mapping (4xx → PluginError):
44	//   - 409 → code='parent-mismatch' with cause: { actualParent, expectedParent }.
45	//     The orchestrator keys off this code to drive the rebase flow.
46	//   - other 4xx → code = envelope.error.code (e.g., 'unknown-version',
47	//     'invalid-path', 'VALIDATION'). Whatever the server sent.
48	//
49	// Error mapping (5xx + connect errors → WorkspaceServerUnavailableError):
50	//   - The host plugin maps this to a retryable-at-orchestrator-level error.
51	//   - The cause carries the underlying socket error / 5xx envelope for logs.
52	//
53	// Response cap: MAX_FRAME (4 MiB). Bigger → drop the connection and surface
54	// WorkspaceServerUnavailableError('response body exceeded cap'). Defensive —
55	// the server doesn't intentionally produce >4 MiB bodies, but a malicious
56	// or compromised server shouldn't be able to OOM the host either.
57	// ---------------------------------------------------------------------------
58	
59	export interface WorkspaceGitHttpClient {
60	  apply(
61	    req: z.infer<typeof WorkspaceApplyRequestSchema>,
62	  ): Promise<z.infer<typeof WorkspaceApplyResponseSchema>>;
63	  read(
64	    req: z.infer<typeof WorkspaceReadRequestSchema>,
65	  ): Promise<z.infer<typeof WorkspaceReadResponseSchema>>;
66	  list(
67	    req: z.infer<typeof WorkspaceListRequestSchema>,
68	  ): Promise<z.infer<typeof WorkspaceListResponseSchema>>;
69	  diff(
70	    req: z.infer<typeof WorkspaceDiffRequestSchema>,
71	  ): Promise<z.infer<typeof WorkspaceDiffResponseSchema>>;
72	}
73	
74	export interface CreateWorkspaceGitHttpClientOptions {
75	  /**
