1	// ---------------------------------------------------------------------------
2	// Test-only host-side Plugin for @ax/workspace-git-server.
3	//
4	// Translates `workspace:*` hooks into git-protocol operations against a
5	// remote `@ax/workspace-git-server` instance. Maintains a per-plugin bare
6	// mirror in a tempdir and shells out to the system `git` binary using the
7	// same paranoid env discipline as the server (with author env added).
8	//
9	// NOT exported from `index.ts`. NOT registered by any preset. The point of
10	// existing is to satisfy `runWorkspaceContract` and the multi-replica /
11	// empty-repo integration tests in Phase 1 — Phase 2 replaces it with a
12	// production plugin that handles shard routing, retry policy, and the rest.
13	// ---------------------------------------------------------------------------
14	
15	import { spawn } from 'node:child_process';
16	import { mkdtempSync, rmSync } from 'node:fs';
17	import { mkdir, readFile, rm, writeFile } from 'node:fs/promises';
18	import { tmpdir } from 'node:os';
19	import { dirname, join } from 'node:path';
20	import {
21	  asWorkspaceVersion,
22	  PluginError,
23	  type Bytes,
24	  type FileChange,
25	  type Plugin,
26	  type WorkspaceApplyInput,
27	  type WorkspaceApplyOutput,
28	  type WorkspaceChange,
29	  type WorkspaceDelta,
30	  type WorkspaceDiffInput,
31	  type WorkspaceDiffOutput,
32	  type WorkspaceListInput,
33	  type WorkspaceListOutput,
34	  type WorkspaceReadInput,
35	  type WorkspaceReadOutput,
36	} from '@ax/core';
37	import { createRepoLifecycleClient } from './repo-lifecycle.js';
38	
39	const PLUGIN_NAME = '@ax/workspace-git-server-test-only';
40	
41	// Author env for commits made by this plugin. Production plugins (Phase 2+)
42	// will route the agent identity through here; for the test-only plugin a
43	// fixed identity keeps the contract stable.
44	const AUTHOR_ENV = {
45	  GIT_AUTHOR_NAME: 'ax-runner',
46	  GIT_AUTHOR_EMAIL: 'ax-runner@example.com',
47	  GIT_COMMITTER_NAME: 'ax-runner',
48	  GIT_COMMITTER_EMAIL: 'ax-runner@example.com',
49	} as const;
50	
51	// Same paranoid env as the server, with PATH widened slightly (test envs
52	// may have git on /usr/local/bin) and author identity for commits.
53	const HOST_GIT_ENV: NodeJS.ProcessEnv = {
54	  GIT_CONFIG_NOSYSTEM: '1',
55	  GIT_CONFIG_GLOBAL: '/dev/null',
56	  GIT_TERMINAL_PROMPT: '0',
57	  HOME: '/nonexistent',
58	  PATH: '/usr/local/bin:/usr/bin:/bin',
59	  ...AUTHOR_ENV,
60	};
61	
62	export interface CreateTestOnlyGitServerPluginOptions {
63	  /**
64	   * Boots a fresh server (or reuses one) and returns the connection info +
65	   * a workspaceId for this plugin instance to operate on. Called once per
66	   * `init()`.
67	   */
68	  boot: () => Promise<{
69	    baseUrl: string;
70	    token: string;
71	    workspaceId: string;
72	  }>;
73	}
74	
75	interface GitResult {
76	  code: number | null;
77	  signal: NodeJS.Signals | null;
78	  stdout: string;
79	  stderr: string;
80	}
81	
82	interface GitOpts {
83	  cwd?: string;
84	  // Bytes to feed via stdin (e.g. for `git diff-tree` etc. — currently unused).
85	  stdin?: Buffer | string;
86	  // Optional extra env merged on top of HOST_GIT_ENV.
87	  extraEnv?: NodeJS.ProcessEnv;
88	}
89	
90	function runGit(args: readonly string[], opts: GitOpts = {}): Promise<GitResult> {
91	  return new Promise((resolve, reject) => {
92	    const env: NodeJS.ProcessEnv = { ...HOST_GIT_ENV, ...(opts.extraEnv ?? {}) };
93	    const child = spawn('git', [...args], {
94	      env,
95	      cwd: opts.cwd,
96	      stdio: [opts.stdin === undefined ? 'ignore' : 'pipe', 'pipe', 'pipe'],
97	    });
98	    const out: Buffer[] = [];
99	    const err: Buffer[] = [];
100	    child.stdout?.on('data', (c: Buffer) => out.push(c));
101	    child.stderr?.on('data', (c: Buffer) => err.push(c));
102	    child.once('error', reject);
103	    child.once('close', (code, signal) => {
104	      resolve({
105	        code,
106	        signal,
107	        stdout: Buffer.concat(out).toString('utf8'),
108	        stderr: Buffer.concat(err).toString('utf8'),
109	      });
110	    });
111	    if (opts.stdin !== undefined) {
112	      child.stdin?.end(opts.stdin);
113	    }
114	  });
115	}
116	
117	// --- Bytes helpers --------------------------------------------------------
118	
119	async function readBlobBytes(
120	  repoDir: string,
121	  oid: string,
122	  path: string,
123	): Promise<Bytes> {
124	  // `git cat-file blob <oid>:<path>` writes the bytes to stdout. Capture as
125	  // raw Buffer (not utf8) to preserve binary content.
126	  return new Promise((resolve, reject) => {
127	    const child = spawn('git', ['-C', repoDir, 'cat-file', 'blob', `${oid}:${path}`], {
128	      env: HOST_GIT_ENV,
129	      stdio: ['ignore', 'pipe', 'pipe'],
130	    });
131	    const chunks: Buffer[] = [];
132	    const errChunks: Buffer[] = [];
133	    child.stdout.on('data', (c: Buffer) => chunks.push(c));
134	    child.stderr.on('data', (c: Buffer) => errChunks.push(c));
135	    child.once('error', reject);
136	    child.once('close', (code) => {
137	      if (code !== 0) {
138	        reject(
139	          new Error(
140	            `git cat-file blob ${oid}:${path} exited ${code}: ${Buffer.concat(errChunks).toString('utf8')}`,
141	          ),
142	        );
143	        return;
144	      }
145	      const buf = Buffer.concat(chunks);
146	      resolve(new Uint8Array(buf.buffer, buf.byteOffset, buf.byteLength));
147	    });
148	  });
149	}
150	
151	// --- Glob -----------------------------------------------------------------
152	
153	// Minimal glob -> regex converter, sufficient for the contract test's `src/**`.
154	// Supports `**` (any path including slashes), `*` (any chars except slash),
155	// `?` (any single char except slash). Other regex specials are escaped.
156	function globToRegex(glob: string): RegExp {
157	  let re = '^';
158	  for (let i = 0; i < glob.length; i++) {
159	    const c = glob[i]!;
160	    if (c === '*') {
161	      if (glob[i + 1] === '*') {
162	        re += '.*';
163	        i++;
164	      } else {
165	        re += '[^/]*';
166	      }
167	    } else if (c === '?') {
168	      re += '[^/]';
169	    } else if ('.+^$(){}[]|\\'.includes(c)) {
170	      re += `\\${c}`;
171	    } else {
172	      re += c;
173	    }
174	  }
175	  re += '$';
176	  return new RegExp(re);
177	}
178	
179	// --- Apply pipeline helpers ----------------------------------------------
180	
181	interface MirrorState {
182	  /** Bare mirror dir for this plugin instance. */
183	  mirror: string;
184	  baseUrl: string;
185	  token: string;
186	  workspaceId: string;
187	  /** URL with embedded path to the bare repo on the server. */
188	  remoteUrl: string;
189	  /** Tracks the last queue tail; ensures hooks serialize per-plugin. */
190	  queue: Promise<unknown>;
191	}
192	
193	function authConfig(token: string): readonly string[] {
194	  return ['-c', `http.extraHeader=Authorization: Bearer ${token}`];
195	}
196	
197	async function fetchMirror(state: MirrorState): Promise<void> {
198	  const r = await runGit(
199	    [
200	      ...authConfig(state.token),
201	      '-C',
202	      state.mirror,
203	      'fetch',
204	      '--prune',
205	      state.remoteUrl,
206	      '+refs/heads/*:refs/heads/*',
207	    ],
208	  );
209	  if (r.code !== 0) {
210	    // First fetch on a freshly-init'd empty mirror against an empty server
211	    // repo can succeed-or-fail depending on git version: many emit a warning
212	    // about the empty repo but exit 0. If it exits non-zero and the message
213	    // mentions "Couldn't find remote ref" or similar emptiness markers, the
214	    // mirror is effectively in the same state — still empty — so swallow.
215	    // Anything else propagates.
216	    const msg = r.stderr.toLowerCase();
217	    if (
218	      msg.includes('empty repository') ||
219	      msg.includes("couldn't find remote ref") ||
220	      msg.includes('does not appear to be a git repository')
221	    ) {
222	      return;
223	    }
224	    throw new Error(`git fetch failed (code ${r.code}): ${r.stderr}`);
225	  }
226	}
227	
228	async function currentMirrorOid(mirror: string): Promise<string | null> {
229	  const r = await runGit([
230	    '-C',
231	    mirror,
232	    'rev-parse',
233	    '--quiet',
234	    '--verify',
235	    'refs/heads/main',
236	  ]);
237	  if (r.code !== 0) return null;
238	  const oid = r.stdout.trim();
239	  return oid.length > 0 ? oid : null;
240	}
241	
242	async function buildScratch(
243	  state: MirrorState,
244	  mirrorHead: string | null,
245	): Promise<string> {
246	  const scratch = mkdtempSync(join(tmpdir(), 'ax-ws-server-scratch-'));
247	  if (mirrorHead === null) {
248	    // Empty baseline: init a working tree on `main`.
249	    const init = await runGit(['init', '-b', 'main', scratch]);
250	    if (init.code !== 0) {
251	      throw new Error(`git init scratch failed: ${init.stderr}`);
252	    }
253	  } else {
254	    // Local clone from the bare mirror — fast, no network. The clone
255	    // automatically checks out the default branch.
256	    const clone = await runGit(['clone', state.mirror, scratch]);
257	    if (clone.code !== 0) {
258	      throw new Error(`git clone scratch failed: ${clone.stderr}`);
259	    }
260	  }
261	  return scratch;
262	}
263	
264	async function applyChanges(
265	  scratch: string,
266	  changes: FileChange[],
267	): Promise<void> {
268	  for (const change of changes) {
269	    const target = join(scratch, change.path);
270	    if (change.kind === 'put') {
271	      await mkdir(dirname(target), { recursive: true });
272	      await writeFile(target, change.content);
273	    } else {
274	      // delete — `force: true` means missing-ok.
275	      await rm(target, { force: true });
276	    }
277	  }
278	}
279	
280	async function commitScratch(
281	  scratch: string,
282	  reason: string | undefined,
283	): Promise<string> {
284	  const add = await runGit(['-C', scratch, 'add', '-A']);
285	  if (add.code !== 0) throw new Error(`git add -A failed: ${add.stderr}`);
286	  const message = reason ?? 'apply';
287	  // --allow-empty so an apply with `changes: []` still produces a new oid.
288	  const commit = await runGit([
289	    '-C',
290	    scratch,
291	    'commit',
292	    '--allow-empty',
293	    '-m',
294	    message,
295	  ]);
296	  if (commit.code !== 0) {
297	    throw new Error(`git commit failed: ${commit.stderr}`);
298	  }
299	  const rp = await runGit(['-C', scratch, 'rev-parse', 'HEAD']);
300	  if (rp.code !== 0) {
301	    throw new Error(`git rev-parse HEAD failed: ${rp.stderr}`);
302	  }
303	  return rp.stdout.trim();
304	}
305	
306	async function pushScratch(
307	  state: MirrorState,
308	  scratch: string,
309	  parent: string | null,
310	): Promise<{ ok: true } | { ok: false; nonFastForward: boolean; stderr: string }> {
311	  // CAS via --force-with-lease: assert remote main matches `<parent>` (empty
312	  // string for the no-prior-commit case). Mismatch -> non-fast-forward error
313	  // surfaced as parent-mismatch.
314	  const lease = parent === null ? '' : parent;
315	  const args = [
316	    ...authConfig(state.token),
317	    '-C',
318	    scratch,
319	    'push',
320	    `--force-with-lease=refs/heads/main:${lease}`,
321	    state.remoteUrl,
322	    'HEAD:refs/heads/main',
323	  ];
324	  const r = await runGit(args);
325	  if (r.code === 0) return { ok: true };
326	  const msg = r.stderr.toLowerCase();
327	  const nonFastForward =
328	    msg.includes('non-fast-forward') ||
329	    msg.includes('non fast forward') ||
330	    msg.includes('stale info') || // --force-with-lease lease mismatch
331	    msg.includes('rejected') ||
332	    msg.includes('failed to push');
333	  return { ok: false, nonFastForward, stderr: r.stderr };
334	}
335	
336	interface DiffEntry {
337	  status: 'A' | 'M' | 'D';
338	  path: string;
339	}
340	
341	async function diffTree(
342	  repoDir: string,
343	  fromOid: string | null,
344	  toOid: string,
345	): Promise<DiffEntry[]> {
346	  // The empty tree object — `git hash-object -t tree /dev/null` is
347	  // 4b825dc642cb6eb9a060e54bf8d69288fbee4904. git knows this constant.
348	  const EMPTY_TREE = '4b825dc642cb6eb9a060e54bf8d69288fbee4904';
349	  const left = fromOid ?? EMPTY_TREE;
350	  const r = await runGit([
351	    '-C',
352	    repoDir,
353	    'diff-tree',
354	    '-r',
355	    '--name-status',
356	    '--no-renames',
357	    '--root', // include diff against initial commit
358	    left,
359	    toOid,
360	  ]);
361	  if (r.code !== 0) {
362	    // diff-tree against the empty tree id is supported, but if anything goes
363	    // wrong, surface the error rather than swallowing.
364	    throw new Error(`git diff-tree failed: ${r.stderr}`);
365	  }
366	  const lines = r.stdout.split('\n').filter((l) => l.length > 0);
367	  const entries: DiffEntry[] = [];
368	  for (const line of lines) {
369	    // Lines look like: "A\tpath" or "M\tpath" or "D\tpath".
370	    // diff-tree --root may emit a leading line that's the commit oid itself
371	    // when `from` is the empty tree; tolerate.
372	    const parts = line.split('\t');
373	    if (parts.length < 2) continue;
374	    const status = parts[0]!;
375	    const path = parts.slice(1).join('\t');
376	    if (status === 'A' || status === 'M' || status === 'D') {
377	      entries.push({ status, path });
378	    }
379	  }
380	  return entries;
381	}
382	
383	function statusToKind(s: 'A' | 'M' | 'D'): WorkspaceChange['kind'] {
384	  if (s === 'A') return 'added';
385	  if (s === 'M') return 'modified';
386	  return 'deleted';
387	}
388	
389	async function buildDelta(
390	  state: MirrorState,
391	  parent: string | null,
392	  newOid: string,
393	  reason: string | undefined,
394	): Promise<WorkspaceDelta> {
395	  const entries = await diffTree(state.mirror, parent, newOid);
396	  const changes: WorkspaceChange[] = entries.map((e) => {
397	    const kind = statusToKind(e.status);
398	    const path = e.path;
399	    if (kind === 'added') {
400	      return {
401	        path,
402	        kind: 'added',
403	        contentAfter: () => readBlobBytes(state.mirror, newOid, path),
404	      };
405	    }
406	    if (kind === 'modified') {
407	      // parent is non-null when status is 'M'; defensive.
408	      const before = parent;
409	      return {
410	        path,
411	        kind: 'modified',
412	        contentBefore: () =>
413	          before === null
414	            ? Promise.reject(new Error('contentBefore unavailable: no parent'))
415	            : readBlobBytes(state.mirror, before, path),
416	        contentAfter: () => readBlobBytes(state.mirror, newOid, path),
417	      };
418	    }
419	    // deleted
420	    const before = parent;
421	    return {
422	      path,
423	      kind: 'deleted',
424	      contentBefore: () =>
425	        before === null
426	          ? Promise.reject(new Error('contentBefore unavailable: no parent'))
427	          : readBlobBytes(state.mirror, before, path),
428	    };
429	  });
430	
431	  const out: WorkspaceDelta = {
432	    before: parent === null ? null : asWorkspaceVersion(parent),
433	    after: asWorkspaceVersion(newOid),
434	    changes,
435	  };
436	  if (reason !== undefined) out.reason = reason;
437	  return out;
438	}
439	
440	// ---------------------------------------------------------------------------
441	// Plugin factory
442	// ---------------------------------------------------------------------------
443	
444	export function createTestOnlyGitServerPlugin(
445	  opts: CreateTestOnlyGitServerPluginOptions,
446	): Plugin {
447	  // Mirror tempdir + queue live in closure scope; populated in init().
448	  let state: MirrorState | null = null;
449	
450	  const enqueue = async <T>(fn: () => Promise<T>): Promise<T> => {
451	    if (state === null) throw new Error('plugin not initialized');
452	    const next = state.queue.then(fn, fn);
453	    state.queue = next.then(
454	      () => undefined,
455	      () => undefined,
456	    );
457	    return next;
458	  };
459	
460	  const parentMismatch = (message: string): PluginError =>
461	    new PluginError({
462	      code: 'parent-mismatch',
463	      plugin: PLUGIN_NAME,
464	      message,
465	    });
466	
467	  return {
468	    manifest: {
469	      name: PLUGIN_NAME,
470	      version: '0.0.0',
471	      registers: [
472	        'workspace:apply',
473	        'workspace:read',
474	        'workspace:list',
475	        'workspace:diff',
476	      ],
477	      calls: [],
478	      subscribes: [],
479	    },
480	
481	    async init({ bus }) {
482	      const { baseUrl, token, workspaceId } = await opts.boot();
483	      const lifecycle = createRepoLifecycleClient({ baseUrl, token });
484	
485	      // 1. Best-effort create. 409 means the test/test-harness already created
486	      // the repo (e.g. multi-replica scenarios share one repo across plugins).
487	      try {
488	        await lifecycle.createRepo(workspaceId);
489	      } catch (err) {
490	        if ((err as Error).message !== 'repo already exists') throw err;
491	      }
492	
493	      // 2. Per-plugin tempdir mirror. Use init --bare for the empty-baseline
494	      // case (the server's repo has no `refs/heads/main` until first push).
495	      // `git clone --mirror` against an empty repo emits a warning and exits
496	      // non-zero on some git versions, so we always init then fetch.
497	      const mirror = mkdtempSync(join(tmpdir(), 'ax-ws-server-mirror-'));
498	      const init = await runGit(['init', '--bare', '-b', 'main', mirror]);
499	      if (init.code !== 0) {
500	        throw new Error(`git init --bare mirror failed: ${init.stderr}`);
501	      }
502	
503	      const remoteUrl = `${baseUrl.replace(/\/$/, '')}/${workspaceId}.git`;
504	
505	      state = {
506	        mirror,
507	        baseUrl,
508	        token,
509	        workspaceId,
510	        remoteUrl,
511	        queue: Promise.resolve(),
512	      };
513	
514	      // Initial fetch — may be a no-op against an empty server repo.
515	      await fetchMirror(state);
516	
517	      // 3. Register the four hooks.
518	      bus.registerService<WorkspaceApplyInput, WorkspaceApplyOutput>(
519	        'workspace:apply',
520	        PLUGIN_NAME,
521	        async (_ctx, input) =>
522	          enqueue(async () => {
523	            if (state === null) throw new Error('plugin not initialized');
524	            // Refresh, then check parent matches mirror head.
525	            await fetchMirror(state);
526	            const mirrorHead = await currentMirrorOid(state.mirror);
527	            const callerParent = input.parent === null ? null : (input.parent as string);
528	
529	            if (mirrorHead === null && callerParent !== null) {
530	              throw parentMismatch(
531	                'mirror has no commits; caller passed a non-null parent',
532	              );
533	            }
534	            if (mirrorHead !== null && callerParent === null) {
535	              throw parentMismatch(
536	                'mirror has commits; caller passed parent: null',
537	              );
538	            }
539	            if (
540	              mirrorHead !== null &&
541	              callerParent !== null &&
542	              mirrorHead !== callerParent
543	            ) {
544	              throw parentMismatch(
545	                'caller parent does not match current mirror head',
546	              );
547	            }
548	
549	            // Build a working tree, apply changes, commit.
550	            const scratch = await buildScratch(state, mirrorHead);
551	            try {
552	              await applyChanges(scratch, input.changes);
553	              const newOid = await commitScratch(scratch, input.reason);
554	
555	              // Push with CAS — if a concurrent writer beat us, this fails as
556	              // non-fast-forward and we surface parent-mismatch.
557	              const push = await pushScratch(state, scratch, mirrorHead);
558	              if (!push.ok) {
559	                if (push.nonFastForward) {
560	                  throw parentMismatch(
561	                    'remote rejected push: non-fast-forward (concurrent writer)',
562	                  );
563	                }
564	                throw new Error(`git push failed: ${push.stderr}`);
565	              }
566	
567	              // Refresh mirror so the just-pushed commit + its blobs are
568	              // available for diff/contentAfter.
569	              await fetchMirror(state);
570	
571	              const delta = await buildDelta(
572	                state,
573	                mirrorHead,
574	                newOid,
575	                input.reason,
576	              );
577	              return {
578	                version: asWorkspaceVersion(newOid),
579	                delta,
580	              };
581	            } finally {
582	              rmSync(scratch, { recursive: true, force: true });
583	            }
584	          }),
585	      );
586	
587	      bus.registerService<WorkspaceReadInput, WorkspaceReadOutput>(
588	        'workspace:read',
589	        PLUGIN_NAME,
590	        async (_ctx, input) =>
591	          enqueue(async () => {
592	            if (state === null) throw new Error('plugin not initialized');
593	            await fetchMirror(state);
594	            const target =
595	              input.version !== undefined
596	                ? (input.version as string)
597	                : await currentMirrorOid(state.mirror);
598	            if (target === null) return { found: false };
599	            // Existence check — `cat-file -e` exits 0 iff the object exists.
600	            const exists = await runGit([
601	              '-C',
602	              state.mirror,
603	              'cat-file',
604	              '-e',
605	              `${target}:${input.path}`,
606	            ]);
607	            if (exists.code !== 0) return { found: false };
608	            const bytes = await readBlobBytes(state.mirror, target, input.path);
609	            return { found: true, bytes };
610	          }),
611	      );
612	
613	      bus.registerService<WorkspaceListInput, WorkspaceListOutput>(
614	        'workspace:list',
615	        PLUGIN_NAME,
616	        async (_ctx, input) =>
617	          enqueue(async () => {
618	            if (state === null) throw new Error('plugin not initialized');
619	            await fetchMirror(state);
620	            const target =
621	              input.version !== undefined
622	                ? (input.version as string)
623	                : await currentMirrorOid(state.mirror);
624	            if (target === null) return { paths: [] };
625	            const r = await runGit([
626	              '-C',
627	              state.mirror,
628	              'ls-tree',
629	              '-r',
630	              '--name-only',
631	              target,
632	            ]);
633	            if (r.code !== 0) {
634	              throw new Error(`git ls-tree failed: ${r.stderr}`);
635	            }
636	            let paths = r.stdout
637	              .split('\n')
638	              .map((l) => l.trim())
639	              .filter((l) => l.length > 0);
640	            if (input.pathGlob !== undefined) {
641	              const re = globToRegex(input.pathGlob);
642	              paths = paths.filter((p) => re.test(p));
643	            }
644	            return { paths };
645	          }),
646	      );
647	
648	      bus.registerService<WorkspaceDiffInput, WorkspaceDiffOutput>(
649	        'workspace:diff',
650	        PLUGIN_NAME,
651	        async (_ctx, input) =>
652	          enqueue(async () => {
653	            if (state === null) throw new Error('plugin not initialized');
654	            await fetchMirror(state);
655	            const from = input.from === null ? null : (input.from as string);
656	            const to = input.to as string;
657	            const delta = await buildDelta(state, from, to, undefined);
658	            return { delta };
659	          }),
660	      );
661	    },
662	
663	    async shutdown() {
664	      if (state !== null) {
665	        try {
666	          rmSync(state.mirror, { recursive: true, force: true });
667	        } catch {
668	          // best-effort
669	        }
670	        state = null;
671	      }
672	    },
673	  };
674	}
