Phase 1 already shipped this in `packages/workspace-git-server/src/shared/shard.ts`:

```ts
// shared/shard.ts (Phase 1, ALREADY EXISTS)
export interface ShardUrlOptions {
  serviceName: string;     // expected to end in "-headless" (the headless svc)
  namespace: string;
  port: number;
  shardIndex: number;
}

export function shardUrl(opts: ShardUrlOptions): string {
  const stsName = opts.serviceName.replace(/-headless$/, '');
  return `http://${stsName}-${opts.shardIndex}.${opts.serviceName}.${opts.namespace}.svc.cluster.local:${opts.port}`;
