// ---------------------------------------------------------------------------

import { shardForWorkspace, shardUrl } from '../shared/shard.js';

export interface ShardLocator {
  /** Headless Service name (typically ends in `-headless`). */
  serviceName: string;
  /** Kubernetes namespace the StatefulSet lives in. */
  namespace: string;
  /** Port the git-server listens on. */
  port: number;
  /** Number of storage-tier shards (== StatefulSet replica count). */
  shards: number;
}

export function shardUrlForWorkspace(
  workspaceId: string,
  opts: ShardLocator,
): string {
  const shardIndex = shardForWorkspace(workspaceId, opts.shards);
  return shardUrl({
    serviceName: opts.serviceName,
    namespace: opts.namespace,
    port: opts.port,
    shardIndex,
  });
}
```

